SELECT COUNT(*)
FROM cvpl
WHERE user_no = #{userNo}
  AND apt_cmplex_no = #{aptCmplexNo}

SELECT *
FROM (SELECT a.*, ROWNUM rnum
      FROM (SELECT cvpl_no, cvpl_ty_cd, cvpl_loc, cvpl_cn, cvpl_stts_cd
                 , cvpl_reg_dt, cvpl_mdf_dt, cvpl_rcpt_dt, cvpl_end_dt
                 , cvpl_prrt, cvpl_file_no, cvpl_ttl, user_no, ho_no, apt_cmplex_no
            FROM cvpl
            WHERE user_no = #{searchVO.userNo}
              AND apt_cmplex_no = #{searchVO.aptCmplexNo}
            ORDER BY cvpl_reg_dt DESC) a
          WHERE ROWNUM <= #{endRow} 
       )
WHERE rnum >= #{startRow}

SELECT COUNT(*)
FROM cvpl
WHERE apt_cmplex_no = #{searchVO.aptCmplexNo}

    AND cvpl_ty_cd = #{searchVO.cvplTyCd}


    AND cvpl_stts_cd = #{searchVO.cvplSttsCd}


    AND cvpl_ttl LIKE '%' || #{searchWord} || '%'

mapper.update:
UPDATE cvpl
SET cvpl_stts_cd = 'CNCL'
WHERE cvpl_no = #{cvplNo}

mapper.select:
SELECT *
FROM (SELECT a.*, ROWNUM rnum
FROM (SELECT c.cvpl_no, cvpl_ty_cd, cvpl_loc, cvpl_cn, cvpl_stts_cd
, cvpl_reg_dt, cvpl_mdf_dt, cvpl_rcpt_dt, cvpl_end_dt
, cvpl_prrt, cvpl_file_no, cvpl_ttl
, c.user_no, m.user_id, m.user_nm, ho_no, apt_cmplex_no
FROM cvpl c
INNER JOIN member m ON (m.user_no = c.user_no)
WHERE apt_cmplex_no = #{searchVO.aptCmplexNo}

    AND cvpl_ty_cd = #{searchVO.cvplTyCd}


    AND cvpl_stts_cd = #{searchVO.cvplSttsCd}


    AND cvpl_ttl LIKE '%' || #{searchWord} || '%'

ORDER BY cvpl_reg_dt DESC) a
 WHERE ROWNUM <= #{endRow} 
)
WHERE rnum >= #{startRow}
